import threading

class ThreadLocalManager:
    _local = threading.local()

    @classmethod
    def set(cls, key, value):
        setattr(cls._local, key, value)

    @classmethod
    def get(cls, key, default=None):
        return getattr(cls._local, key, default)

    @classmethod
    def clear(cls):
        cls._local.__dict__.clear()
